import{bQ as l,aL as t,u as i,G as o}from"./chunks/framework.jc7iVf2j.js";const u=JSON.parse('{"title":"常见逻辑谬误","description":"简中互联网上常见的逻辑谬误","frontmatter":{"title":"常见逻辑谬误","tags":["必读"],"categories":["必读"],"date":"2026-03-19T00:00:00.000Z","description":"简中互联网上常见的逻辑谬误","head":[["link",{"rel":"canonical","href":"https://knotens.org/posts/常见逻辑谬误"}]]},"headers":[],"relativePath":"posts/常见逻辑谬误.md","filePath":"posts/常见逻辑谬误.md","lastUpdated":1778461527000}');const a=l({name:"posts/常见逻辑谬误.md"},[["render",function(l,u,a,q,e,r){return t(),i("div",null,[...u[0]||(u[0]=[o('<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>后真相时代，中文互联网充斥着<strong>无效的公共辩论</strong>。</p><ul><li>逻辑谬误只能证伪，不能证真（原则：</li><li>能指出对方的谬误，不代表你就是对的。逻辑谬误只能证伪，不能证真。</li><li>认识诡辩术不会让辩论变得更诚实， 只会让诡辩变得更高级。</li></ul><h2 id="t0-极高频-源于情绪宣泄与思维惰性" tabindex="-1">T0：极高频，源于情绪宣泄与思维惰性 <a class="header-anchor" href="#t0-极高频-源于情绪宣泄与思维惰性" aria-label="Permalink to &quot;T0：极高频，源于情绪宣泄与思维惰性&quot;">​</a></h2><ol><li>诉诸人身 借由与当前论题无关的个人特质，作为驳斥对方或支持己方论证的理据。又名对人不对事、因人废言/因人纳言。 <ul><li>人身攻击：又名扣帽子，让听众在还无法深入了解、思考之前，就率先被某人身上负面的标签所影响，使听众对其事有种&quot;先入为主&quot;的负面认知与不良的刻板印象。</li><li>诉诸动机：借由质疑提出主张者的动机（如利益相关），而论证或明示暗示其主张不合理。</li><li>诉诸伪善：又名&quot;你也一样/彼此彼此&quot;、臭虫论、&quot;那又怎么说&quot;论，主张某人的行为和他的主张有不一致的地方，但却指不出该主张哪里有错。&quot;你也一样&quot;谬误是一种冤冤相报谬误。</li><li>诉诸权威：以权威人士言论作为论证依据，将权威观点直接等同于真理。</li></ul></li><li>诉诸情感 又名情绪勒索、道德绑架。用情绪反应替代逻辑论证。通过操弄恐惧、怜悯、愤怒等强烈情绪，让对方失去理性判断能力。 <ul><li>示例：&quot;你不支持这个政策，就是冷血&quot;（道德绑架）</li><li>示例：&quot;想想那些在战争中牺牲的父辈们&quot;（本身不是论证，而是呼吁，只有当它取代论证时才成为谬误）</li></ul></li><li>稻草人谬误 有意或无意地通过夸大、曲解甚至完全捏造对方的论点，使其变得荒谬。针对新的替身论点进行攻击，再宣称已推翻对方论点的论证。例如，把对方&quot;应该降低税率&quot;曲解成&quot;主张完全取消税收&quot;。</li><li>假两难谬误 又名非黑即白、伪二分法。论证时错误地将可能性局限于两个对立选项，而实际存在未被提及的替代方案（忽视中间地带）。</li><li>身边统计学 用个人经验或者孤例替代证据或言之有理的论证。</li></ol><hr><h2 id="t1-非常常见-源于-试图-讲道理时对因果和概括的错误理解" tabindex="-1">T1：非常常见，源于&quot;试图&quot;讲道理时对因果和概括的错误理解 <a class="header-anchor" href="#t1-非常常见-源于-试图-讲道理时对因果和概括的错误理解" aria-label="Permalink to &quot;T1：非常常见，源于&quot;试图&quot;讲道理时对因果和概括的错误理解&quot;">​</a></h2><ol><li>确认偏差 又名验证性偏见，认定一个观点后，（无意识）地选择性地搜集有利细节，忽略不利或矛盾的信息，来支持已有的观点。</li><li>轻率概括 又名以偏概全。不正确地运用简单枚举归纳推理，在未积累足够材料时草率作出普遍性结论。</li><li>滑坡谬误 使用连串的因果推论，却夸大了每个环节中的因果强度，将&quot;可能性&quot;转化为&quot;必然性&quot;，从而得到不合理的结论。 <ul><li>示例：&quot;如果允许同性婚姻，接下来就会允许人兽婚姻，最后社会就会崩溃&quot;</li></ul></li><li>归因谬误 仅因二者先后发生就强加因果，夸大了关联性，忽视了偶然性，将相关性看作因果性。 <ul><li>示例：当城市里的冰淇淋销量大幅增加时，同期的溺水死亡人数也会随之飙升。有这两者之间并没有直接的因果关系，而是共同受一个&quot;第三变量&quot;的影响：受夏季高温影响，冰淇淋卖的多，游泳的人变多。</li></ul></li><li>歧义谬误 又名偷换概念。利用双重含义的语句或含糊不清存有歧义的陈述来误导或歪曲事实。 <ul><li>示例：&quot;英国和美国的某些地方&quot;可理解为&quot;英国所有地方及美国部分地方&quot;或&quot;英国部分地方及美国部分地方&quot;。</li><li>示例：&quot;他是我刚认识的小明的哥哥&quot;可理解为&quot;我刚认识小明，他是小明的哥哥&quot;或&quot;我刚认识他，他是小明的哥哥&quot;。</li><li>示例：&quot;儿子生性病母倍感安慰&quot;(2010 粤语新闻标题)可理解为&quot;儿子生性(生性，粤语，懂事)，病母倍感安慰&quot;或&quot;儿子生性病，母倍感安慰&quot;。</li></ul></li></ol><hr><h2 id="t2-常见-多见于论点被攻击时的强行找补或和稀泥" tabindex="-1">T2：常见，多见于论点被攻击时的强行找补或和稀泥 <a class="header-anchor" href="#t2-常见-多见于论点被攻击时的强行找补或和稀泥" aria-label="Permalink to &quot;T2：常见，多见于论点被攻击时的强行找补或和稀泥&quot;">​</a></h2><ol><li>诉诸纯洁 又名没有真正的苏格兰人，当某个观点被证明是错误的时候，通过事后增加前提条件、修改规则、引入特例来开脱错误。不断修正、净化论据论点的方式，来驳斥对论证瑕疵的批评或反面论据。 <ul><li>示例：某商家声称自家手环能&quot;防辐射&quot;。科学家用仪器检测后指出手环无任何防护作用。商家却辩称：&quot;那是因为你们用的是普通仪器，只有我们公司的专用检测仪才能测出效果。&quot;</li><li>示例：股评师预测&quot;某只股票明天必涨&quot;，结果第二天暴跌。被质疑后，他说：&quot;我说的是&#39;趋势性上涨&#39;，短期波动不算。&quot;</li><li>示例：A：“男人都是很坚强的”，B：“我见过一个男人哭了”，A：“那不是真正的男人”</li></ul></li><li>诉诸中庸 认定多个冲突观点中找出折衷观点就一定是最佳解，认为&quot;真理在中间&quot;的谬误。</li><li>举证责任倒置 认定举证的责任不在提出观点的人，而是在质疑观点的人。谁主张，谁举证。</li><li>机械类比 将两个本质不同的事物按其表面相似性进行机械比较并得出结论。</li></ol><hr><h2 id="t3-较常见-但往往需要特定的对话语境或更隐蔽的逻辑闭环" tabindex="-1">T3：较常见，但往往需要特定的对话语境或更隐蔽的逻辑闭环 <a class="header-anchor" href="#t3-较常见-但往往需要特定的对话语境或更隐蔽的逻辑闭环" aria-label="Permalink to &quot;T3：较常见，但往往需要特定的对话语境或更隐蔽的逻辑闭环&quot;">​</a></h2><ol><li>诉诸荒谬 通过把对方的主张推向极端或荒谬的结果，以此来否定对方论点的推理方式。</li><li>预设提问 在提问中预先置入假设，使对方无论如何作答都只能显得有问题，具有煽动性。 <ul><li>示例：&quot;你爸妈知道你是gay吗？&quot;——预设了&quot;你是gay&quot;这一前提。</li></ul></li><li>谬误谬误 又名谬导致误。因论述水平差，又或者论述中有谬误，就判定这结论一定是错误的。</li><li>赌徒谬误 错误认为随机事件的概率会随连续结果改变、认为不相关的独立随机事件中存在可掌握的规律。忽视独立事件的客观概率恒定性。</li><li>循环论证 论点的前提中已包含结论。 <ul><li>示例：《胡说八道经》是完美无瑕的，我们之所以知晓这一点，是因为在至高无上的《胡说八道经》里曾经有写道：“凡《胡说八道经》所言皆为真善美，尔等不得稍有疑虑”。</li></ul></li></ol>',14)])])}]]);export{u as __pageData,a as default};
